ALTER TABLE "coupons"."coupon_applications" ADD CONSTRAINT "ck_coupon_applications__coupon_discount_amount_non_negative" CHECK ((coupon_discount_amount IS NULL) OR (coupon_discount_amount >= (0)::numeric)), ADD CONSTRAINT "ck_coupon_applications__gross_amount_at_application_non_nega" CHECK ((gross_amount_at_application IS NULL) OR (gross_amount_at_application >= (0)::numeric)), ADD CONSTRAINT "ck_coupon_applications__net_amount_after_coupon_non_negative" CHECK ((net_amount_after_coupon IS NULL) OR (net_amount_after_coupon >= (0)::numeric)), ADD CONSTRAINT "ck_coupon_applications__row_version_positive" CHECK (row_version > 0), ADD CONSTRAINT "uq_coupon_applications__idempotency_key" UNIQUE ("idempotency_key");
-- Modify "coupon_rule_groups" table
ALTER TABLE "coupons"."coupon_rule_groups" ADD CONSTRAINT "ck_coupon_rule_groups__effective_window" CHECK ((effective_to IS NULL) OR (effective_to > effective_from)), ADD CONSTRAINT "ck_coupon_rule_groups__evaluation_priority_non_negative" CHECK ((evaluation_priority IS NULL) OR (evaluation_priority >= 0)), ADD CONSTRAINT "ck_coupon_rule_groups__row_version_positive" CHECK (row_version > 0);
