ALTER TABLE "coupons"."coupon_rules" ADD CONSTRAINT "ck_coupon_rules__effective_window" CHECK ((effective_to IS NULL) OR (effective_to > effective_from)), ADD CONSTRAINT "ck_coupon_rules__row_version_positive" CHECK (row_version > 0);
-- Modify "coupons" table
ALTER TABLE "coupons"."coupons" ADD CONSTRAINT "ck_coupons__denomination_value_non_negative" CHECK ((denomination_value IS NULL) OR (denomination_value >= (0)::numeric)), ADD CONSTRAINT "ck_coupons__maximum_discount_amount_non_negative" CHECK ((maximum_discount_amount IS NULL) OR (maximum_discount_amount >= (0)::numeric)), ADD CONSTRAINT "ck_coupons__minimum_gross_amount_non_negative" CHECK ((minimum_gross_amount IS NULL) OR (minimum_gross_amount >= (0)::numeric)), ADD CONSTRAINT "ck_coupons__row_version_positive" CHECK (row_version > 0);
